const ems = global.get('ems') || {};
const now = Date.now();
const startedAt = context.get('startedAt') || now;
context.set('startedAt', startedAt);

function manualEvent() {
    const enabled = !!ems.core?.ems_enabled;
    return {
        topic: 'ems/ai/manual',
        type: 'manual',
        key: `manual:${now}`,
        importance: 'normal',
        status: enabled ? 'READY' : 'OFF',
        status_display: enabled ? 'EMS běží' : 'EMS vypnuté',
        reason: enabled ? 'manual_request' : 'ems_disabled',
        reason_display: enabled ? 'Ruční dotaz na stav EMS' : 'EMS je vypnuté nebo zakázané',
        human_hint: 'Uživatel ručně požádal o krátký komentář aktuálního stavu EMS.',
        recommendation_hint: 'Stručně shrň aktuální stav. Nenavrhuj přímé ovládání zařízení.',
        allowed_topics: ['aktuální stav EMS', 'bezpečné doporučení z recommendation_hint'],
        forbidden_topics: ['přímé ovládání zařízení', 'servisní zásahy'],
        notify: false,
        speak: false,
        silent: false,
        ts: now
    };
}

if (now - startedAt < 90000 && !msg.force) return null;

const event = msg.force ? manualEvent() : (msg.ems_ai_event || msg.payload?.event || ems.ai_event);
if (!event || typeof event !== 'object') return null;
if (!msg.force && event.silent) return null;

const required = ['topic','type','key','importance','status_display','reason_display','human_hint','recommendation_hint','allowed_topics','forbidden_topics','notify','speak','silent'];
const missing = required.filter(k => event[k] === undefined || event[k] === null);
if (missing.length) {
    node.warn(`EMS AI event missing fields: ${missing.join(', ')}`);
    return null;
}

const eventKey = event.key || `${event.topic}:${event.type}:${event.status || event.status_display}:${event.reason || event.reason_display}`;
if (!msg.force && String(event.reason || eventKey).includes('ems_disabled')) return null;

const lastEventKey = context.get('lastEventKey');
const lastRun = context.get('lastRun') || 0;
if (!msg.force) {
    if (eventKey === lastEventKey) return null;
    if (now - lastRun < 120000) return null;
}

context.set('lastEventKey', eventKey);
context.set('lastRun', now);
msg.ems_ai_event = {...event, key: eventKey};
msg.ems_snapshot = ems;
msg.ems_ai_started_at = now;
return msg;

const ems = msg.ems_snapshot || {};
const core = ems.core || {};
const event = msg.ems_ai_event || ems.ai_event || {};
const prompt = "Jsi domácí EMS analytik. Odpovídej pouze česky, stručně, maximálně 3 věty.\nNikdy si nevymýšlej údaje. Nikdy nepopisuj JSON ani jeho strukturu.\nEMS je deterministické řízení a ty pouze vysvětluješ jeho stav a rozhodnutí.\nPokud je důvod \"ems_disabled\", znamená to, že EMS je vypnuté nebo zakázané, ne porucha komunikace.\nPoužívej přednostně české hodnoty reason_display a status_display, pokud jsou ve vstupu.\nAI nesmí sama navrhovat akce mimo recommendation_hint ve vstupním eventu.\nŘekni, co se právě děje v domě a co doporučuješ.";

const snapshot = {
    timestamp: new Date().toISOString(),
    event,
    core: {
        ems_enabled: !!core.ems_enabled,
        hdo_state: core.hdo_state,
        battery_soc: core.battery_soc,
        battery_power: core.battery_power,
        pv_power: core.pv_power,
        grid_power: core.grid_power,
        surplus_power: core.surplus_power,
        deficit_power: core.deficit_power,
        house_power: core.house_power,
        target_soc: core.target_soc || ems.plan?.battery?.target_soc,
        effective_min_soc: core.effective_min_soc || ems.plan?.battery?.effective_min_soc,
        forecast_day_type_tomorrow: core.forecast_day_type_tomorrow || ems.plan?.strategy?.day_type_tomorrow
    }
};

if (event.type === 'wallbox' && ems.wallbox) {
    snapshot.wallbox = {
        mode: ems.wallbox.mode,
        reason: ems.wallbox.reason,
        reason_display: ems.wallbox.reason_display,
        id3_charge_enable: !!ems.wallbox.id3?.charge_enable,
        id4_charge_enable: !!ems.wallbox.id4?.charge_enable,
        selected_car: ems.wallbox.selected_car,
        current_a: Math.max(ems.wallbox.id3?.current_a || 0, ems.wallbox.id4?.current_a || 0)
    };
} else if (event.type === 'boiler' && ems.boiler) {
    snapshot.boiler = {
        mode: ems.boiler.mode,
        reason: ems.boiler.reason,
        reason_display: ems.boiler.reason_display,
        bottom_t1: !!ems.boiler.bottom_t1,
        bottom_t2: !!ems.boiler.bottom_t2,
        pergola_t1: !!ems.boiler.pergola_t1,
        pergola_t2: !!ems.boiler.pergola_t2
    };
} else if ((event.type === 'battery_grid' || event.type === 'battery_balance') && ems.battery_grid) {
    snapshot.battery_grid = {
        mode: ems.battery_grid.mode,
        reason: ems.battery_grid.reason,
        reason_display: ems.battery_grid.reason_display,
        current_a: ems.battery_grid.current_a,
        charge_enable: !!ems.battery_grid.charge_enable
    };
} else if (event.type === 'safety' && ems.safety) {
    snapshot.safety = {
        voltage: ems.safety.voltage,
        ac_in_status: ems.safety.ac_in?.status,
        ac_in_status_display: ems.safety.ac_in?.status_display,
        ac_in_reason: ems.safety.ac_in?.reason,
        ac_in_reason_display: ems.safety.ac_in?.reason_display,
        emergency_status: ems.safety.emergency?.status,
        emergency_status_display: ems.safety.emergency?.status_display,
        emergency_reason: ems.safety.emergency?.reason,
        emergency_reason_display: ems.safety.emergency?.reason_display
    };
}

msg.ems_ai_snapshot = snapshot;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    model: 'gemma3:4b',
    prompt: `${prompt}

Stav:
${JSON.stringify(snapshot, null, 2)}`,
    stream: false,
    options: { temperature: 0.1, num_predict: 120 }
};
return msg;

const durationMs = Date.now() - (msg.ems_ai_started_at || Date.now());
const response = msg.payload && typeof msg.payload.response === 'string' ? msg.payload.response.trim() : '';
const model = msg.payload?.model || flow.get('ems_ai_model') || 'gemma3:4b';
const eventKey = msg.ems_ai_event?.key || 'unknown';

const status = {
    state: response ? 'ok' : 'error',
    model,
    duration_ms: durationMs,
    event_key: eventKey,
    timestamp: new Date().toISOString(),
    error: response ? null : 'empty_response'
};

if (!response) {
    return [null, { topic: 'ems/ai/status', payload: status, retain: true }, { topic: 'ems/ai/error', payload: JSON.stringify(status), retain: true }];
}
return [
    { topic: 'ems/ai/comment', payload: response, retain: true },
    { topic: 'ems/ai/status', payload: status, retain: true },
    null
];
